function selectAirport(code){
  document.querySelectorAll(".airport-card").forEach(b=>b.classList.remove("active"));
  const active=[...document.querySelectorAll(".airport-card")].find(b=>b.innerText.includes(code));
  if(active) active.classList.add("active");
  const item=airportCharts[code];
  document.getElementById("selectedAirportChip").textContent=code;
  document.getElementById("selectedAirportName").textContent=item.name;
  showChartInViewer(item.chart);
  const maps=document.getElementById("googleMapsLink");
  if(maps) maps.href=item.maps||`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(code+" "+item.name)}`;
  const extra=document.getElementById("chartExtraLinks");
  if(extra){extra.innerHTML=(item.links||[]).map(link=>`<button class="ghost-button" type="button" onclick="showChartInViewer('${link.url}')">${link.label}</button>`).join("");}
}
async function loadSchedule(showErrors=true){
  const guest = document.getElementById("scheduleGuestMessage");
  const app = document.getElementById("waveScheduleApp");
  if(!token){
    if(guest) guest.classList.remove("hidden");
    if(app) app.classList.add("hidden");
    return;
  }
  if(guest) guest.classList.add("hidden");
  if(app) app.classList.remove("hidden");

  try{
    const res = await fetch("/api/wave-schedule", {headers: authHeaders()});
    const data = await res.json();
    if(res.ok && Array.isArray(data.flights) && data.flights.length > 0){
      waveSchedule = data.flights;
    }else{
      waveSchedule = JSON.parse(JSON.stringify(defaultWaveSchedule));
    }
  }catch(err){
    waveSchedule = JSON.parse(JSON.stringify(defaultWaveSchedule));
  }
  renderWaveCalendar();
}

function renderWaveCalendar(){
  const cal = document.getElementById("waveCalendar");
  if(!cal) return;
  const admin = canEditSchedule();

  cal.innerHTML = waveDays.map(day => `
    <section class="wave-day-card">
      <div class="wave-day-header">${day.label}</div>
      <div class="wave-day-grid">
        ${waveTimes.map(time => `
          <div class="wave-time-row">
            <div class="wave-time-label">${time}</div>
            <div class="wave-slot-pair">
              ${waveAircraft.map(ac => renderWaveSlot(day.date, time, ac, admin)).join("")}
            </div>
          </div>
        `).join("")}
      </div>
    </section>
  `).join("");

  if(admin) attachScheduleDragHandlers();
}

function renderWaveSlot(date, time, aircraft, admin){
  const flights = waveSchedule.filter(f => f.date === date && f.time === time && f.aircraft === aircraft);
  return `
    <div class="wave-slot ${aircraft === "C172" ? "slot-c172" : "slot-c152"}" data-date="${date}" data-time="${time}" data-aircraft="${aircraft}">
      <div class="slot-aircraft">${aircraft}</div>
      ${flights.map(f => renderFlightCard(f, admin)).join("") || '<div class="empty-slot">—</div>'}
    </div>
  `;
}

function renderFlightCard(f, admin){
  const exam = String(f.note || "").toUpperCase().includes("EXAM");
  return `
    <div class="flight-card ${f.aircraft === "C172" ? "flight-c172" : "flight-c152"} ${exam ? "exam-flight" : ""}" draggable="${admin ? "true" : "false"}" data-id="${f.id}" oncontextmenu="openSlotEditMenu(event, '${f.id}')">
      <strong>${f.student}</strong>
      <div class="flight-tags">
        <span class="instructor-tag ${f.instructor === "Amir" ? "tag-amir" : "tag-avi"}">${f.instructor}</span>
        <span class="aircraft-tag">${f.aircraft}</span>
        ${f.note ? `<span class="note-tag">${f.note}</span>` : ""}
      </div>
    </div>
  `;
}

function attachScheduleDragHandlers(){
  document.querySelectorAll(".flight-card").forEach(card => {
    card.addEventListener("dragstart", e => {
      e.dataTransfer.setData("text/plain", card.dataset.id);
      card.classList.add("dragging");
    });
    card.addEventListener("dragend", () => card.classList.remove("dragging"));
  });

  document.querySelectorAll(".wave-slot").forEach(slot => {
    slot.addEventListener("dragover", e => {
      e.preventDefault();
      slot.classList.add("drop-target");
    });
    slot.addEventListener("dragleave", () => slot.classList.remove("drop-target"));
    slot.addEventListener("drop", e => {
      e.preventDefault();
      slot.classList.remove("drop-target");
      const id = e.dataTransfer.getData("text/plain");
      const flight = waveSchedule.find(f => f.id === id);
      if(!flight) return;
      flight.date = slot.dataset.date;
      flight.time = slot.dataset.time;
      flight.aircraft = slot.dataset.aircraft;
      renderWaveCalendar();
      toast("Schedule changed. Press Save changes.");
    });
  });
}

async function saveWaveSchedule(){
  if(!canEditSchedule()) return toast("Admin only");
  try{
    const res = await fetch("/api/wave-schedule", {
      method:"POST",
      headers:{...authHeaders(), "Content-Type":"application/json"},
      body:JSON.stringify({flights: waveSchedule})
    });
    const data = await res.json().catch(()=>({}));
    if(!res.ok) throw new Error(data.detail || "Could not save schedule");
    toast("Training wave schedule saved");
  }catch(err){
    toast(err.message);
  }
}

async function resetWaveSchedule(){
  if(!canEditSchedule()) return toast("Admin only");
  waveSchedule = JSON.parse(JSON.stringify(defaultWaveSchedule));
  renderWaveCalendar();
  await saveWaveSchedule();
}


const waveStudents = ["Nir K", "Nir D", "Ofek", "Harel", "Lior", "Aviad", "Ahmad"];
const waveInstructors = ["Avi", "Amir"];
let slotEditFlightId = null;

function openSlotEditMenu(event, flightId){
  if(!canEditSchedule()) return;
  event.preventDefault();
  event.stopPropagation();

  const flight = waveSchedule.find(f => f.id === flightId);
  if(!flight) return;

  slotEditFlightId = flightId;
  const menu = document.getElementById("slotEditMenu");
  const studentSelect = document.getElementById("slotEditStudent");
  const instructorSelect = document.getElementById("slotEditInstructor");
  if(!menu || !studentSelect || !instructorSelect) return;

  studentSelect.innerHTML = waveStudents.map(s => `<option value="${s}">${s}</option>`).join("");
  studentSelect.value = flight.student;
  instructorSelect.value = flight.instructor;

  const x = Math.min(event.clientX, window.innerWidth - 300);
  const y = Math.min(event.clientY, window.innerHeight - 260);
  menu.style.left = x + "px";
  menu.style.top = y + "px";
  menu.classList.remove("hidden");
}

function closeSlotEditMenu(){
  const menu = document.getElementById("slotEditMenu");
  if(menu) menu.classList.add("hidden");
  slotEditFlightId = null;
}

function applySlotEdit(){
  if(!canEditSchedule()) return toast("Admin only");
  const flight = waveSchedule.find(f => f.id === slotEditFlightId);
  if(!flight) return closeSlotEditMenu();

  const studentSelect = document.getElementById("slotEditStudent");
  const instructorSelect = document.getElementById("slotEditInstructor");

  flight.student = studentSelect.value;
  flight.instructor = instructorSelect.value;

  closeSlotEditMenu();
  renderWaveCalendar();
  toast("Flight updated. Press Save changes.");
}

document.addEventListener("click", (event) => {
  const menu = document.getElementById("slotEditMenu");
  if(menu && !menu.classList.contains("hidden") && !menu.contains(event.target)){
    closeSlotEditMenu();
  }
});

document.addEventListener("keydown", (event) => {
  if(event.key === "Escape") closeSlotEditMenu();
});


let adminFis = JSON.parse(localStorage.getItem("adminFis") || '["Avi","Amir"]');
let adminAirplanes = JSON.parse(localStorage.getItem("adminAirplanes") || '[{"type":"C172","number":"C172"},{"type":"C152","number":"C152"}]');

function renderAdminLists(){
  const fiList = document.getElementById("fiAdminList");
  if(fiList) fiList.innerHTML = adminFis.map(fi => `<span>${fi}</span>`).join("");

  const airplaneList = document.getElementById("airplaneAdminList");
  if(airplaneList) airplaneList.innerHTML = adminAirplanes.map(a => `<span>${a.type}${a.number ? " · " + a.number : ""}</span>`).join("");
}

function addFiFromAdmin(){
  const input = document.getElementById("fiNameInput");
  const name = (input?.value || "").trim();
  if(!name) return toast("Enter FI name");
  if(!adminFis.includes(name)) adminFis.push(name);
  localStorage.setItem("adminFis", JSON.stringify(adminFis));
  if(input) input.value = "";
  renderAdminLists();
  toast("FI added");
}

function addAirplaneFromAdmin(){
  const type = document.getElementById("airplaneTypeInput")?.value || "C172";
  const number = (document.getElementById("airplaneNumberInput")?.value || "").trim();
  adminAirplanes.push({type, number});
  localStorage.setItem("adminAirplanes", JSON.stringify(adminAirplanes));
  const input = document.getElementById("airplaneNumberInput");
  if(input) input.value = "";
  renderAdminLists();
  toast("Airplane added");
}

function saveTrainingWaveSettings(){
  const name = document.getElementById("trainingWaveName")?.value || "Training wave";
  const start = document.getElementById("trainingWaveStart")?.value || "2026-05-03";
  const end = document.getElementById("trainingWaveEnd")?.value || "2026-05-10";
  localStorage.setItem("trainingWaveSettings", JSON.stringify({name,start,end}));
  toast("Training wave dates saved");
}

document.addEventListener("DOMContentLoaded", renderAdminLists);
